import{_ as a,o as e,c as d,ai as r}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第十六课：仓位管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/16-position-management.md","filePath":"guide/16-position-management.md","lastUpdated":0}'),h={name:"guide/16-position-management.md"};function n(i,t,l,o,s,b){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="第十六课-仓位管理" tabindex="-1">第十六课：仓位管理 <a class="header-anchor" href="#第十六课-仓位管理" aria-label="Permalink to “第十六课：仓位管理”">​</a></h1><p>仓位管理是<strong>最重要的风险控制手段</strong>，也是区分散户和成熟投资者的关键。</p><h2 id="一、什么是仓位" tabindex="-1">一、什么是仓位？ <a class="header-anchor" href="#一、什么是仓位" aria-label="Permalink to “一、什么是仓位？”">​</a></h2><p><strong>仓位 = 你买了多少股票/基金 ÷ 你总共有多少钱</strong></p><table tabindex="0"><thead><tr><th>仓位状态</th><th>含义</th></tr></thead><tbody><tr><td>空仓</td><td>100%现金，0%股票</td></tr><tr><td>轻仓</td><td>20-30%持股</td></tr><tr><td>半仓</td><td>50%持股</td></tr><tr><td>重仓</td><td>70-80%持股</td></tr><tr><td>满仓</td><td>100%持股</td></tr><tr><td>杠杆</td><td>借钱炒股（危险！）</td></tr></tbody></table><h2 id="二、为什么仓位管理重要" tabindex="-1">二、为什么仓位管理重要？ <a class="header-anchor" href="#二、为什么仓位管理重要" aria-label="Permalink to “二、为什么仓位管理重要？”">​</a></h2><h3 id="没有仓位管理的后果" tabindex="-1">没有仓位管理的后果 <a class="header-anchor" href="#没有仓位管理的后果" aria-label="Permalink to “没有仓位管理的后果”">​</a></h3><blockquote><p>满仓跌50% → 需要涨100%才能回本</p></blockquote><h3 id="有仓位管理的好处" tabindex="-1">有仓位管理的好处 <a class="header-anchor" href="#有仓位管理的好处" aria-label="Permalink to “有仓位管理的好处”">​</a></h3><blockquote><p>50%仓位跌50% → 只亏25%，容易回本</p></blockquote><blockquote><p>💡 <strong>控制仓位，就是在控制风险。</strong></p></blockquote><h2 id="三、仓位管理原则" tabindex="-1">三、仓位管理原则 <a class="header-anchor" href="#三、仓位管理原则" aria-label="Permalink to “三、仓位管理原则”">​</a></h2><h3 id="_1-不满仓原则" tabindex="-1">1. 不满仓原则 <a class="header-anchor" href="#_1-不满仓原则" aria-label="Permalink to “1. 不满仓原则”">​</a></h3><p><strong>永远不要满仓</strong>。预留现金，跌了可以补仓拉低成本。</p><h3 id="_2-分批建仓原则" tabindex="-1">2. 分批建仓原则 <a class="header-anchor" href="#_2-分批建仓原则" aria-label="Permalink to “2. 分批建仓原则”">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>操作</th></tr></thead><tbody><tr><td>一次建仓</td><td>一下子全买进去</td></tr><tr><td>分批建仓</td><td>先买30%，跌了再买30%，再跌再买40%</td></tr></tbody></table><blockquote><p>建议新手用<strong>分批建仓</strong>，降低买贵的风险。</p></blockquote><h3 id="_3-大盘仓位原则" tabindex="-1">3. 大盘仓位原则 <a class="header-anchor" href="#_3-大盘仓位原则" aria-label="Permalink to “3. 大盘仓位原则”">​</a></h3><table tabindex="0"><thead><tr><th>大盘状态</th><th>建议仓位</th></tr></thead><tbody><tr><td>大盘强势上涨</td><td>60-80%</td></tr><tr><td>大盘震荡</td><td>30-50%</td></tr><tr><td>大盘弱势下跌</td><td>10-30%</td></tr></tbody></table><h2 id="四、新手仓位建议" tabindex="-1">四、新手仓位建议 <a class="header-anchor" href="#四、新手仓位建议" aria-label="Permalink to “四、新手仓位建议”">​</a></h2><h3 id="保守型-推荐新手" tabindex="-1">保守型（推荐新手） <a class="header-anchor" href="#保守型-推荐新手" aria-label="Permalink to “保守型（推荐新手）”">​</a></h3><table tabindex="0"><thead><tr><th>总资金</th><th>仓位</th><th>股票金额</th></tr></thead><tbody><tr><td>10万</td><td>30%</td><td>3万</td></tr><tr><td>10万</td><td>预留</td><td>7万（等待机会）</td></tr></tbody></table><h3 id="激进型-有经验" tabindex="-1">激进型（有经验） <a class="header-anchor" href="#激进型-有经验" aria-label="Permalink to “激进型（有经验）”">​</a></h3><table tabindex="0"><thead><tr><th>总资金</th><th>仓位</th><th>股票金额</th></tr></thead><tbody><tr><td>10万</td><td>60%</td><td>6万</td></tr><tr><td>10万</td><td>预留</td><td>4万（补仓用）</td></tr></tbody></table><h2 id="五、仓位管理口诀" tabindex="-1">五、仓位管理口诀 <a class="header-anchor" href="#五、仓位管理口诀" aria-label="Permalink to “五、仓位管理口诀”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>新手三成仓，不满不空常；</span></span>
<span class="line"><span>跌了有钱补，涨了不后悔。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="六、补仓的技巧" tabindex="-1">六、补仓的技巧 <a class="header-anchor" href="#六、补仓的技巧" aria-label="Permalink to “六、补仓的技巧”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>补仓建议</th></tr></thead><tbody><tr><td>跌5%</td><td>可以补一次</td></tr><tr><td>跌10%</td><td>可以再补</td></tr><tr><td>跌20%</td><td>谨慎，可能是趋势变了</td></tr><tr><td>跌30%</td><td>先分析原因，不要盲目补</td></tr></tbody></table><blockquote><p>⚠️ <strong>补仓是双刃剑</strong>：补对了降低成本加快回本，补错了加大亏损。</p></blockquote><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>你有10万元本金，现在大盘在低位震荡，你打算怎么分配仓位？说说你的理由。</p></blockquote><hr><p><strong>下一课预告</strong>：仓位管理学完了，下一课学习<strong>止损与止盈</strong>——如何在合适的位置退出。</p>`,33)])])}const k=a(h,[["render",n]]);export{p as __pageData,k as default};
